// ============================================
// AUTH CHECK — reject if X-API-Key is missing or invalid
// ============================================
const requestHeaders = $input.first().json.headers || {};
const providedKey = (requestHeaders['x-api-key'] || '').toLowerCase().trim();
const staticData = $getWorkflowStaticData('global');
const validKey = (staticData.apiKey || 'gw-dev-api-key-change-in-production').toLowerCase().trim();

if (!providedKey || providedKey !== validKey) {
  return [{
    json: {
      success: false,
      error: 'Unauthorized: missing or invalid X-API-Key header'
    },
    meta: { httpStatus: 401 }
  }];
}

// Pass through original input data on success
return [$input.first()];

// ============================================
// VALIDATE + PARSE SYNC PAYLOAD
// spa_id must be included in every row written to GS
// ============================================
const body = $input.first().json.body;
const spaId = $input.first().json.params?.spa_id;

if (!spaId) {
  return [{ json: { success: false, error: 'Missing spa_id in URL' }, meta: { httpStatus: 400 } }];
}

const { type, data } = body || {};
if (!type || !data) {
  return [{ json: { success: false, error: 'Missing type or data in body' }, meta: { httpStatus: 400 } }];
}

if (!['booking', 'chat_log'].includes(type)) {
  return [{ json: { success: false, error: `Invalid type: ${type}. Must be 'booking' or 'chat_log'` }, meta: { httpStatus: 400 } }];
}

// Normalize data shape — spa_id is ALWAYS the first column
const normalized = type === 'booking' ? {
  'spa_id': spaId,
  'Thời gian': data.time || new Date().toISOString(),
  'Tên khách': data.name || '',
  'Số điện thoại': data.phone || '',
  'Dịch vụ': data.service || '',
  'Ghi chú': data.note || '',
  'Zalo ID': data.senderId || '',
  'Trạng thái': 'Mới đặt',
  'Chi nhánh': data.branch || ''
} : {
  'spa_id': spaId,
  'Thời gian': data.time || new Date().toISOString(),
  'Zalo ID': data.senderId || '',
  'Tên khách': data.senderName || '',
  'Tin nhắn khách': data.customerMessage || '',
  'Phản hồi AI': data.aiReply || '',
  'Loại': data.category || 'Tư vấn',
  'Đặt lịch': data.isBooking ? 'Có' : 'Không'
};

return [{
  json: {
    success: true,
    syncType: type,
    spaId: spaId,
    rowData: normalized
  }
}];

// ============================================
// AUTH CHECK — Dashboard endpoint
// ============================================
const requestHeaders = $input.first().json.headers || {};
const providedKey = (requestHeaders['x-api-key'] || '').toLowerCase().trim();
const staticData = $getWorkflowStaticData('global');
const validKey = (staticData.apiKey || 'gw-dev-api-key-change-in-production').toLowerCase().trim();

if (!providedKey || providedKey !== validKey) {
  return [{
    json: { success: false, error: 'Unauthorized: missing or invalid X-API-Key header' },
    meta: { httpStatus: 401 }
  }];
}

return [$input.first()];

// ============================================
// DASHBOARD CALCULATION
// Aggregated stats for today, scoped to spa_id
// ============================================
const logRows = $('GS - Read LogChat (today)').all();
const bookingRows = $('GS - Read DatCho (today)').all();
const now = new Date();
const hcmNow = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Ho_Chi_Minh' }));
const dateStr = hcmNow.toISOString().split('T')[0];

const totalMessages = logRows.length;
const totalBookings = bookingRows.length;
const pendingBookings = bookingRows.filter(r => r.json['Trạng thái'] === 'Mới đặt').length;
const confirmedBookings = bookingRows.filter(r => r.json['Trạng thái'] === 'Đã xác nhận').length;
const completedBookings = bookingRows.filter(r => r.json['Trạng thái'] === 'Hoàn thành').length;
const conversionRate = totalBookings > 0
  ? ((confirmedBookings + completedBookings) / totalBookings * 100).toFixed(1)
  : '0.0';

// Top services
const svcMap = {};
bookingRows.forEach(r => {
  const svc = r.json['Dịch vụ'] || 'Khác';
  svcMap[svc] = (svcMap[svc] || 0) + 1;
});
const topServices = Object.entries(svcMap)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, count]) => ({ name, count }));

// Recent bookings (last 10)
const recentBookings = [...bookingRows].sort((a, b) => new Date(b.json['Thời gian'] || 0) - new Date(a.json['Thời gian'] || 0)).slice(0, 10).map((r, idx) => ({
  id: String(idx + 1),
  name: r.json['Tên khách'],
  service: r.json['Dịch vụ'],
  status: r.json['Trạng thái'],
  time: r.json['Thời gian']?.split('T')[1]?.slice(0, 5) || ''
}));

return [{
  json: {
    success: true,
    data: {
      date: dateStr,
      totalMessages,
      totalBookings,
      pendingBookings,
      confirmedBookings,
      completedBookings,
      conversionRate,
      topServices,
      recentBookings
    }
  }
}];

// ============================================
// AUTH CHECK — Customers endpoint
// ============================================
const requestHeaders = $input.first().json.headers || {};
const providedKey = (requestHeaders['x-api-key'] || '').toLowerCase().trim();
const staticData = $getWorkflowStaticData('global');
const validKey = (staticData.apiKey || 'gw-dev-api-key-change-in-production').toLowerCase().trim();

if (!providedKey || providedKey !== validKey) {
  return [{
    json: { success: false, error: 'Unauthorized: missing or invalid X-API-Key header' },
    meta: { httpStatus: 401 }
  }];
}

return [$input.first()];

// ============================================
// CUSTOMER LIST — unique by phone, with search and pagination
// Only rows matching spa_id are returned (GS Read filtered above)
// ============================================
const rows = $('GS - Read DatCho (All Customers)').all();
const params = $('Webhook - Customers').first().json.query || {};
const page = Math.max(parseInt(params.page) || 1, 1);
const limit = Math.min(Math.max(parseInt(params.limit) || 20, 1), 100);
const search = (params.search || '').toLowerCase();

// Deduplicate by phone
const customerMap = {};
rows.forEach(r => {
  const phone = r.json['Số điện thoại'];
  if (!phone) return;
  if (!customerMap[phone]) {
    customerMap[phone] = {
      name: r.json['Tên khách'] || '',
      phone,
      totalBookings: 0,
      lastBooking: r.json['Thời gian'],
      status: r.json['Trạng thái'],
      service: r.json['Dịch vụ'] || ''
    };
  }
  customerMap[phone].totalBookings++;
});

let customers = Object.values(customerMap);

// Search filter
if (search) {
  customers = customers.filter(c =>
    (c.name && c.name.toLowerCase().includes(search)) ||
    c.phone.includes(search) ||
    (c.service && c.service.toLowerCase().includes(search))
  );
}

const total = customers.length;
const offset = (page - 1) * limit;
const paginated = customers.slice(offset, offset + limit).map((c, i) => ({
  id: String(offset + i + 1),
  ...c
}));

return [{
  json: {
    success: true,
    data: paginated,
    total,
    page,
    limit,
    totalPages: Math.ceil(total / limit)
  }
}];

// ============================================
// AUTH CHECK — Bookings List endpoint
// ============================================
const requestHeaders = $input.first().json.headers || {};
const providedKey = (requestHeaders['x-api-key'] || '').toLowerCase().trim();
const staticData = $getWorkflowStaticData('global');
const validKey = (staticData.apiKey || 'gw-dev-api-key-change-in-production').toLowerCase().trim();

if (!providedKey || providedKey !== validKey) {
  return [{
    json: { success: false, error: 'Unauthorized: missing or invalid X-API-Key header' },
    meta: { httpStatus: 401 }
  }];
}

return [$input.first()];

// ============================================
// BOOKINGS LIST — filterable by status, paginated
// Uses Google Sheets row number as stable ID
// ============================================
const rows = $('GS - Read DatCho (All Bookings)').all();
const params = $('Webhook - Bookings List').first().json.query || {};
const page = Math.max(parseInt(params.page) || 1, 1);
const limit = Math.min(Math.max(parseInt(params.limit) || 20, 1), 100);
const statusFilter = params.status;

let bookings = rows.map((r, index) => ({
  id: String(index + 2), // Row 1 is header, data starts at row 2
  name: r.json['Tên khách'] || '',
  phone: r.json['Số điện thoại'] || '',
  service: r.json['Dịch vụ'] || '',
  note: r.json['Ghi chú'] || '',
  status: r.json['Trạng thái'] || '',
  time: r.json['Thời gian'] || '',
  branch: r.json['Chi nhánh'] || '',
  spaId: r.json['spa_id']
}));

if (statusFilter) {
  bookings = bookings.filter(b => b.status === statusFilter);
}

// Sort by time descending (most recent first)
bookings.sort((a, b) => {
  if (!a.time) return 1;
  if (!b.time) return -1;
  return new Date(b.time).getTime() - new Date(a.time).getTime();
});

const total = bookings.length;
const offset = (page - 1) * limit;
const paginated = bookings.slice(offset, offset + limit);

return [{
  json: {
    success: true,
    data: paginated,
    total,
    page,
    limit,
    totalPages: Math.ceil(total / limit)
  }
}];

// ============================================
// AUTH CHECK — Update Booking endpoint
// ============================================
const requestHeaders = $input.first().json.headers || {};
const providedKey = (requestHeaders['x-api-key'] || '').toLowerCase().trim();
const staticData = $getWorkflowStaticData('global');
