if (!providedKey || providedKey !== validKey) {
  return [{
    json: { success: false, error: 'Unauthorized: missing or invalid X-API-Key header' },
    meta: { httpStatus: 401 }
  }];
}

return [$input.first()];

// ============================================
// UPDATE BOOKING STATUS by row number
// Booking ID is 1-based row number (row 2 = first data row)
// ============================================
const body = $input.first().json.body;
const spaId = $input.first().json.params?.spa_id;
const bookingId = $input.first().json.params?.id;
const newStatus = body?.status;
const validStatuses = ['Mới đặt', 'Đã xác nhận', 'Hoàn thành', 'Đã hủy'];

if (!newStatus || !validStatuses.includes(newStatus)) {
  return [{
    json: { success: false, error: `Invalid status: ${newStatus}. Must be one of: ${validStatuses.join(', ')}` },
    meta: { httpStatus: 400 }
  }];
}

// bookingId is 1-based row number
const rowIndex = parseInt(bookingId) || 0;
if (rowIndex < 2) {
  return [{
    json: { success: false, error: 'Invalid booking ID. Must be >= 2 (header is row 1).' },
    meta: { httpStatus: 400 }
  }];
}

return [{
  json: {
    success: true,
    bookingId: bookingId,
    rowIndex: rowIndex,
    spaId: spaId,
    newStatus: newStatus,
    updatedAt: new Date().toISOString()
  }
}];

