// ============================================
// GET SERVICES — parse from GS rows
// ============================================
const rows = $('GS - Read Services').all();
const services = rows.map(r => ({
  id: r.json['ID'] || r.json['Dịch vụ'],
  name: r.json['Dịch vụ'] || '',
  price: parseInt(r.json['Giá']) || 0,
  description: r.json['Mô tả'] || '',
  active: r.json['Trạng thái'] !== 'Ẩn'
}));

return [{ json: { success: true, data: services } }];

// ============================================
// CREATE SERVICE — parse and prepare row data
// ============================================
const body = $input.first().json.body;
const spaId = $input.first().json.params?.spa_id;
const serviceId = 'svc-' + Date.now();

if (!body.name) {
  return [{ json: { success: false, error: 'Missing service name' }, meta: { httpStatus: 400 } }];
}

const newService = {
  'spa_id': spaId,
  'ID': serviceId,
  'Dịch vụ': body.name,
  'Giá': String(body.price || 0),
  'Mô tả': body.description || '',
  'Trạng thái': 'Hiện'
};

return [{
  json: {
    success: true,
    serviceId: serviceId,
    rowData: newService
  }
}];

// ============================================
// UPDATE SERVICE — parse and prepare row data
// ============================================
const body = $input.first().json.body;
const id = $input.first().json.params?.id;

if (!id) {
  return [{ json: { success: false, error: 'Missing service ID' }, meta: { httpStatus: 400 } }];
}

const updated = {
  'Dịch vụ': body.name,
  'Giá': String(body.price || 0),
  'Mô tả': body.description || '',
  'Trạng thái': body.active !== false ? 'Hiện' : 'Ẩn'
};

return [{
  json: {
    success: true,
    serviceId: id,
    rowData: updated
  }
}];

// ============================================
