    json: { success: false, error: 'Unauthorized: missing or invalid X-API-Key header' },
    meta: { httpStatus: 401 }
  }];
}

return [$input.first()];

// ============================================
// CHAT LOGS — paginated with filters, scoped to spa_id
// ============================================
const rows = $('GS - Read LogChat (All)').all();
const params = $('Webhook - Chat Logs').first().json.query || {};
const page = Math.max(parseInt(params.page) || 1, 1);
const limit = Math.min(Math.max(parseInt(params.limit) || 20, 1), 100);
const dateFilter = params.date;
const senderFilter = params.sender;

let logs = rows.map((r, index) => ({
  id: String(index + 2), // Row 1 is header
  senderId: r.json['Zalo ID'] || '',
  senderName: r.json['Tên khách'] || '',
  customerMessage: r.json['Tin nhắn khách'] || '',
  aiReply: r.json['Phản hồi AI'] || '',
  category: r.json['Loại'] || '',
  isBooking: r.json['Đặt lịch'] === 'Có',
  time: r.json['Thời gian'] || ''
}));

// Apply filters
if (dateFilter) {
  logs = logs.filter(l => l.time && l.time.includes(dateFilter));
}
if (senderFilter) {
  logs = logs.filter(l => l.senderId === senderFilter);
}

// Sort by time descending
logs.sort((a, b) => {
  if (!a.time) return 1;
  if (!b.time) return -1;
  return new Date(b.time).getTime() - new Date(a.time).getTime();
});

const total = logs.length;
const offset = (page - 1) * limit;
const paginated = logs.slice(offset, offset + limit);

return [{
  json: {
    success: true,
    data: paginated,
    total,
    page,
    limit,
    totalPages: Math.ceil(total / limit)
  }
}];
